  document.querySelectorAll('.memory-text-item').forEach(element=>element.addEventListener('blur',async()=>{const text=element.textContent.trim();if(text){await window.jarvis.update('memories',element.dataset.id,{text});state=await window.jarvis.getState();render()}}));
  document.querySelectorAll('.pin-memory').forEach(button=>button.addEventListener('click',async()=>{const memory=state.memories.find(item=>item.id===button.dataset.id);await window.jarvis.update('memories',memory.id,{pinned:!memory.pinned});state=await window.jarvis.getState();render()}));
