  $('#apply-free-preset')?.addEventListener('click',()=>{const recommended=state.connectionStatus?.ai?.recommended;if(!recommended)return;syncAIDraft();aiDraft.route=recommended.waterfall.map(entry=>({...entry}));aiDraft.taskRoutes=Object.fromEntries(Object.entries(recommended.taskRoutes).map(([profile,entry])=>[profile,{...entry}]));render();toast('Recommended free routing loaded. Verify provider models, then save.')});
  $('#add-ai-route')?.addEventListener('click',()=>{syncAIDraft();const provider=$('#ai-add-provider').value;aiDraft.route.push(newAIRoute(provider));render();setTimeout(()=>document.querySelector('.ai-route-row:last-child .ai-route-model')?.focus(),0)});
  document.querySelectorAll('.ai-route-provider').forEach(select=>select.addEventListener('change',()=>{syncAIDraft();const entry=aiDraft.route[Number(select.dataset.index)];entry.provider=select.value;entry.model=AI_PROVIDERS[select.value].defaultModel;entry.baseURL='';entry.credentialSaved=(state.connectionStatus?.ai?.route||[]).some(item=>item.provider===select.value&&item.credentialSaved);render()}));
  document.querySelectorAll('.ai-route-model,.ai-route-base,.ai-route-enabled').forEach(input=>input.addEventListener('change',syncAIDraft));
  document.querySelectorAll('.ai-task-enabled,.ai-task-model,.ai-task-base').forEach(input=>input.addEventListener('change',()=>{syncAIDraft();render()}));
  document.querySelectorAll('.ai-task-provider').forEach(select=>select.addEventListener('change',()=>{syncAIDraft();const profile=select.closest('.ai-task-row').dataset.profile;const entry=aiDraft.taskRoutes[profile];entry.provider=select.value;entry.model=AI_PROVIDERS[select.value].defaultModel;entry.baseURL='';render()}));
  document.querySelectorAll('.remove-ai-route').forEach(button=>button.addEventListener('click',()=>{syncAIDraft();aiDraft.route.splice(Number(button.dataset.index),1);render()}));
  document.querySelectorAll('.move-ai-route').forEach(button=>button.addEventListener('click',()=>moveAIRoute(Number(button.dataset.index),Number(button.dataset.direction))));
  document.querySelectorAll('.ai-route-row').forEach(row=>{row.addEventListener('dragstart',event=>{syncAIDraft();aiDraggedIndex=Number(row.dataset.index);row.classList.add('dragging');event.dataTransfer.effectAllowed='move'});row.addEventListener('dragend',()=>{aiDraggedIndex=null;row.classList.remove('dragging');document.querySelectorAll('.ai-route-row').forEach(item=>item.classList.remove('drag-target'))});row.addEventListener('dragover',event=>{event.preventDefault();event.dataTransfer.dropEffect='move';row.classList.add('drag-target')});row.addEventListener('dragleave',()=>row.classList.remove('drag-target'));row.addEventListener('drop',event=>{event.preventDefault();const target=Number(row.dataset.index);if(aiDraggedIndex===null||target===aiDraggedIndex)return;const [entry]=aiDraft.route.splice(aiDraggedIndex,1);aiDraft.route.splice(target,0,entry);aiDraggedIndex=null;render()})});
  $('#ai-waterfall-form')?.addEventListener('submit',async event=>{event.preventDefault();syncAIDraft();const button=event.submitter;button.disabled=true;button.textContent='Saving…';try{await window.jarvis.saveAIWaterfall({route:aiDraft.route,keys:aiDraft.keys,taskRoutes:aiDraft.taskRoutes,confirmations:aiDraft.confirmations});state=await window.jarvis.getState();aiDraft=null;render();toast('Verified-free AI routing saved securely.')}catch(error){button.disabled=false;button.textContent='Save routing';toast(error.message)}});
  $('#disconnect-ai')?.addEventListener('click',async()=>{if(!confirm('Forget every saved AI key and clear the waterfall?'))return;await window.jarvis.disconnectAI();state=await window.jarvis.getState();aiDraft=null;render();toast('AI keys and waterfall removed.')});
  $('#spotify-connection-form')?.addEventListener('submit',async event=>{event.preventDefault();const button=event.submitter;button.disabled=true;button.textContent='Waiting for Spotify…';try{const profile=await window.jarvis.connectSpotify($('#spotify-client-id').value.trim());state=await window.jarvis.getState();render();toast(`Spotify connected as ${profile.displayName}.`)}catch(error){button.disabled=false;button.textContent='Connect Spotify';toast(error.message)}});
  $('#disconnect-spotify')?.addEventListener('click',async()=>{await window.jarvis.disconnectSpotify();state=await window.jarvis.getState();render();toast('Spotify disconnected.')});
  $('#google-connection-form')?.addEventListener('submit',async event=>{event.preventDefault();const button=event.submitter;button.disabled=true;button.textContent='Waiting for Google…';try{const features=[...document.querySelectorAll('[name="google-feature"]:checked')].map(input=>input.value);const profile=await window.jarvis.connectGoogle({clientId:$('#google-client-id').value.trim(),features});state=await window.jarvis.getState();render();toast(`Google connected as ${profile.name}.`)}catch(error){button.disabled=false;button.textContent='Connect Google';toast(error.message)}});
  $('#disconnect-google')?.addEventListener('click',async()=>{await window.jarvis.disconnectGoogle();state=await window.jarvis.getState();render();toast('Google disconnected.')});
  document.querySelectorAll('.service-connection-form').forEach(form=>form.addEventListener('submit',async event=>{event.preventDefault();const button=event.submitter;const connectorId=form.dataset.connector;button.disabled=true;button.textContent='Connecting…';try{const payload={connectorId,token:form.querySelector('.service-credential')?.value.trim()||'',clientId:form.querySelector('.service-credential')?.value.trim()||'',freePlanConfirmed:Boolean(form.querySelector('.service-free-confirm')?.checked)};if(connectorId==='microsoft')payload.features=[...form.querySelectorAll('[name="microsoft-feature"]:checked')].map(input=>input.value);const result=await window.jarvis.connectService(payload);state=await window.jarvis.getState();render();toast(`${connectorId} connected${result.accountLabel?` as ${result.accountLabel}`:''}.`)}catch(error){button.disabled=false;button.textContent=`Connect ${connectorId}`;toast(friendlyError(error))}}));
  document.querySelectorAll('.disconnect-service').forEach(button=>button.addEventListener('click',async()=>{await window.jarvis.disconnectService(button.dataset.connector);state=await window.jarvis.getState();render();toast(`${button.dataset.connector} disconnected.`)}));
  $('#install-browser-bridge')?.addEventListener('click',async()=>{try{const setup=await window.jarvis.installBrowserBridge();toast(`Chrome setup folder opened. In chrome://extensions, enable Developer mode and load this folder. Extension ID: ${setup.extensionId}`)}catch(error){toast(error.message)}});
  document.querySelectorAll('.native-permission').forEach(button=>button.addEventListener('click',async()=>{try{const status=await window.jarvis.nativeRequest('permissions.request',{kind:button.dataset.kind});toast(`${button.dataset.kind}: ${status[button.dataset.kind]||'request completed'}`)}catch(error){toast(error.message)}}));
  $('#enable-voice-permissions')?.addEventListener('click',async event=>{const button=event.currentTarget;button.disabled=true;button.textContent='Waiting for macOS…';try{await window.jarvis.requestVoicePermissions();state=await window.jarvis.getState();render();toast('Microphone and Speech Recognition are enabled.')}catch(error){state=await window.jarvis.getState();render();toast(error.message)}});
  document.querySelectorAll('.open-voice-privacy').forEach(button=>button.addEventListener('click',()=>window.jarvis.openVoicePrivacySettings(button.dataset.kind)));
  $('#open-dictation-settings')?.addEventListener('click',()=>window.jarvis.openDictationSettings());
  $('#run-diagnostics')?.addEventListener('click',async event=>{const button=event.currentTarget;button.disabled=true;button.textContent='Checking…';try{await window.jarvis.runDiagnostics();state=await window.jarvis.getState();render();toast('Jarvis health check completed.')}catch(error){button.disabled=false;button.textContent='Run health check';toast(friendlyError(error))}});
  $('#export-diagnostics')?.addEventListener('click',async()=>{const file=await window.jarvis.exportDiagnostics();toast(file?'Redacted diagnostic report exported.':'Export canceled.')});
  $('#install-whisper-binary')?.addEventListener('click',async event=>{const button=event.currentTarget;button.disabled=true;button.textContent='Installing…';try{await window.jarvis.installWhisperBinary();state=await window.jarvis.getState();render();toast('whisper.cpp installed.')}catch(error){button.disabled=false;button.textContent='Install with Homebrew';toast(friendlyError(error))}});
  document.querySelectorAll('.whisper-model').forEach(button=>button.addEventListener('click',async()=>{const model=button.dataset.model;const installed=Boolean(state.connectionStatus?.native?.whisper?.[model]);button.disabled=true;button.textContent=installed?'Removing…':'Downloading…';try{if(installed)await window.jarvis.removeWhisperModel(model);else await window.jarvis.installWhisperModel(model);state=await window.jarvis.getState();render();toast(installed?`${model}.en removed.`:`${model}.en installed and verified.`)}catch(error){button.disabled=false;button.textContent=installed?'Remove':'Download & verify';toast(friendlyError(error))}}));
  $('#reopen-setup')?.addEventListener('click',async()=>{state=await window.jarvis.updatePreferences({setupStep:0,onboardingComplete:false});$('#onboarding').classList.remove('hidden');renderSetup()});
