function setupReadiness(){const native=state.connectionStatus?.native||{};const whisper=native.whisper||{};const permissions=native.permissions||{};return{app:native.connected,voice:permissions.microphone==='authorized'&&(permissions.speech==='authorized'||(whisper.binary&&(whisper.base||whisper.tiny))),offlineAI:state.connectionStatus?.ai?.localCompute?.code!=='NOT_CHECKED',cloud:state.connectionStatus?.ai?.connected,browser:state.connectionStatus?.browser?.connected,spotify:state.connectionStatus?.spotify?.connected,google:state.connectionStatus?.google?.connected}}
function setupStatus(ready,label,detail){return `<article class="setup-status ${ready?'ready':'pending'}"><i>${ready?'✓':'·'}</i><div><strong>${label}</strong><small>${detail}</small></div><b>${ready?'READY':'OPTIONAL'}</b></article>`}
function renderSetup(){const host=$('#setup-content');if(!host||!state)return;const step=Math.max(0,Math.min(5,Number(state.preferences.setupStep||0)));const ready=setupReadiness();const native=state.connectionStatus?.native||{};const whisper=native.whisper||{};const ollama=state.connectionStatus?.ai?.ollama||{};const permissions=native.permissions||{};const pages=[
  `<div class="hero-orb" aria-hidden="true"></div><p class="eyebrow">OPEN-SOURCE macOS ASSISTANT</p><h1 id="onboarding-title">Your Mac, one command away.</h1><p>Jarvis works without an account. Optional credentials are entered only inside the app, encrypted locally, and are never bundled with the source code or diagnostic exports.</p><div class="principles"><span>⌘ Push-to-talk</span><span>◈ Local memory</span><span>✓ Risk-based approval</span></div>`,
  `<p class="eyebrow">01 · APPLICATION</p><h1 id="onboarding-title">Install identity</h1><p>A stable signed app keeps macOS permissions attached to Jarvis across launches.</p>${setupStatus(native.connected,'Native companion',native.connected?'Protocol is connected.':'Build the companion with Xcode.')}${setupStatus(location.pathname.includes('/Applications/'),'Application install',location.pathname.includes('/Applications/')?'Running from an installed bundle.':'Developer mode is fine for testing; use the signed installer for stable permissions.')}`,
  `<p class="eyebrow">02 · VOICE</p><h1 id="onboarding-title">Push-to-talk readiness</h1><p>Jarvis requests Microphone and Speech Recognition separately. Offline Whisper remains available when Apple does not expose an on-device recognizer.</p>${setupStatus(permissions.microphone==='authorized','Microphone',permissions.microphone||'Not requested')}${setupStatus(permissions.speech==='authorized','Speech Recognition',permissions.speech||'Not requested')}<button id="setup-request-voice" class="primary" ${native.connected?'':'disabled'}>Request voice permissions</button>`,
  `<p class="eyebrow">03 · OFFLINE INTELLIGENCE</p><h1 id="onboarding-title">Cool, local fallbacks</h1><p>Local models use two threads, bounded context, and whole-system thermal checks. base.en handles normal transcription; tiny.en is the lower-load fallback.</p>${setupStatus(ollama.available&&ollama.hasRecommendedModel,'Ollama · qwen2.5:1.5b',ollama.hasRecommendedModel?'Recommended small model installed.':ollama.available?'Ollama is running; install the recommended model.':'Open the Ollama app, then retry. LM Studio can also be configured later.')}${setupStatus(whisper.binary,'whisper.cpp',whisper.binary?'whisper-cli is installed.':'Install through Homebrew or manually.')}${setupStatus(whisper.base,'base.en q5',whisper.base?'Verified model installed.':'57 MB verified download.')}${setupStatus(whisper.tiny,'tiny.en q5',whisper.tiny?'Verified model installed.':'31 MB low-load fallback.')}<div class="setup-actions-row">${ollama.available&&!ollama.hasRecommendedModel?'<button id="setup-ollama-model" class="secondary">Install qwen2.5:1.5b</button>':''}<button id="setup-whisper-binary" class="secondary" ${whisper.binary?'disabled':''}>${whisper.binary?'Binary installed':'Install binary'}</button><button class="secondary setup-whisper-model" data-model="base" ${whisper.base?'disabled':''}>${whisper.base?'base.en installed':'Install base.en'}</button><button class="secondary setup-whisper-model" data-model="tiny" ${whisper.tiny?'disabled':''}>${whisper.tiny?'tiny.en installed':'Install tiny.en'}</button></div>`,
  `<p class="eyebrow">04 · OPTIONAL CONNECTIONS</p><h1 id="onboarding-title">Add only what you use</h1><p>Nothing here is required. Free AI routing supports Gemini, Groq, Mistral, OpenRouter, NVIDIA developer endpoints, Ollama, and LM Studio. Productivity connectors include Google, GitHub, Microsoft 365, Notion, Todoist, Tavily, Spotify, and the Chrome bridge.</p>${setupStatus(ready.cloud,'AI route',ready.cloud?'A verified-free route is ready.':'Optional—local capabilities still work.')}${setupStatus(ready.browser,'Chrome bridge',ready.browser?'Extension connected.':'Optional for page reading and ordinary controls.')}${setupStatus(ready.spotify,'Spotify',ready.spotify?'Connected.':'Desktop playback controls work without Premium OAuth.')}${setupStatus(ready.google,'Google Workspace',ready.google?'Connected.':'Optional for Gmail, Calendar, Drive, Contacts, and Tasks.')}<button id="setup-open-connections" class="secondary">Configure connections</button>`,
  `<p class="eyebrow">05 · READINESS</p><h1 id="onboarding-title">Jarvis is ready to work.</h1><p>Optional services may remain disconnected. The assistant will degrade honestly and keep typed local commands available.</p>${setupStatus(ready.app,'Local core',ready.app?'Native companion connected.':'Local Electron commands remain available; native features need the companion.')}${setupStatus(ready.voice,'Voice path',ready.voice?'A private microphone path is ready.':'Typed input remains available.')}${setupStatus(true,'Safety boundary','Capability registry, previews, and risk confirmation are active.')}<button id="setup-health-check" class="secondary">Run final health check</button>`
];host.innerHTML=`<div class="setup-progress" aria-label="Setup progress">${Array.from({length:6},(_,index)=>`<i class="${index<=step?'active':''}"></i>`).join('')}</div><div class="setup-body">${pages[step]}</div><footer class="setup-footer"><button id="setup-back" class="secondary" ${step===0?'disabled':''}>Back</button><small>Step ${step+1} of 6</small>${step===5?'<button id="setup-finish" class="primary large">Enter Jarvis</button>':`<button id="setup-next" class="primary large">${step===0?'Begin setup':'Continue'}</button>`}</footer>`;bindSetup(step)}
function bindSetup(step){$('#setup-back')?.addEventListener('click',async()=>{state=await window.jarvis.updatePreferences({setupStep:Math.max(0,step-1)});renderSetup()});$('#setup-next')?.addEventListener('click',async()=>{state=await window.jarvis.updatePreferences({setupStep:Math.min(5,step+1)});renderSetup()});$('#setup-request-voice')?.addEventListener('click',async event=>{const button=event.currentTarget;button.disabled=true;button.textContent='Waiting for macOS…';try{await window.jarvis.requestVoicePermissions();state=await window.jarvis.getState();renderSetup()}catch(error){button.disabled=false;button.textContent='Request voice permissions';toast(friendlyError(error))}});$('#setup-ollama-model')?.addEventListener('click',async event=>{event.currentTarget.disabled=true;event.currentTarget.textContent='Installing…';try{await window.jarvis.installRecommendedOllamaModel();state=await window.jarvis.getState();renderSetup()}catch(error){toast(friendlyError(error));renderSetup()}});$('#setup-whisper-binary')?.addEventListener('click',async event=>{event.currentTarget.disabled=true;event.currentTarget.textContent='Installing…';try{await window.jarvis.installWhisperBinary();state=await window.jarvis.getState();renderSetup()}catch(error){toast(friendlyError(error));renderSetup()}});document.querySelectorAll('.setup-whisper-model').forEach(button=>button.addEventListener('click',async()=>{button.disabled=true;button.textContent='Downloading…';try{await window.jarvis.installWhisperModel(button.dataset.model);state=await window.jarvis.getState();renderSetup()}catch(error){toast(friendlyError(error));renderSetup()}}));$('#setup-open-connections')?.addEventListener('click',()=>{$('#onboarding').classList.add('hidden');showScreen('connections')});$('#setup-health-check')?.addEventListener('click',async event=>{event.currentTarget.disabled=true;event.currentTarget.textContent='Checking…';try{await window.jarvis.runDiagnostics();state=await window.jarvis.getState();toast('Health check completed.');renderSetup()}catch(error){toast(friendlyError(error));renderSetup()}});$('#setup-finish')?.addEventListener('click',async()=>{state=await window.jarvis.updatePreferences({setupStep:5,onboardingComplete:true});$('#onboarding').classList.add('hidden');render();setTimeout(()=>$('#command-input')?.focus(),100)})}

document.querySelectorAll('.nav-item').forEach(button=>button.addEventListener('click',()=>showScreen(button.dataset.screen)));
window.jarvis.onState(next=>{state=next;render();if(!state.preferences.onboardingComplete&&!$('#onboarding').classList.contains('hidden'))renderSetup()}); window.jarvis.onTimer(timer=>{state.timer=timer;if(activeScreen==='command')render()}); window.jarvis.onFocusInput(()=>{showScreen('command');setTimeout(()=>$('#command-input')?.focus(),50)});
window.jarvis.getState().then(initial=>{state=initial;document.documentElement.dataset.motion=state.preferences.reduceMotion?'reduced':'full';if(!state.preferences.onboardingComplete){$('#onboarding').classList.remove('hidden');renderSetup()}render()});
window.jarvis.onSpeechTranscript(payload=>routeVoiceTranscript(payload));
window.jarvis.onSpeechError(message=>toast(message));
window.jarvis.onAssistantStream(payload=>{const card=$('#streaming-answer');if(!card)return;if(payload.reset){activeStreamRequestId=payload.requestId;activeStreamText='';card.querySelector('p').textContent='';card.classList.remove('complete','interrupted')}if(activeStreamRequestId&&payload.requestId!==activeStreamRequestId)return;card.classList.remove('hidden');if(payload.delta){activeStreamText+=payload.delta;card.querySelector('p').textContent+=payload.delta}const status=card.querySelector('.stream-status');if(status)status.textContent=payload.interrupted?'Interrupted · use Regenerate to retry':payload.done?'Complete':card.querySelector('p').textContent?'Responding…':'Connecting…';if(payload.interrupted)card.classList.add('interrupted');if(payload.done){pendingUserText='';card.classList.add('complete')}});
window.jarvis.onWhisperProgress(payload=>{const progress=$('#whisper-progress');if(!progress)return;progress.classList.remove('hidden');const percent=payload.total?Math.min(100,Math.round(payload.received/payload.total*100)):0;progress.querySelector('i').style.width=`${percent}%`;progress.querySelector('span').textContent=payload.total?`${payload.model}.en · ${percent}%`:`${payload.model}.en · ${Math.round(payload.received/1024/1024)} MB`});
